import React, { useState, useEffect, useRef } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
import { INTENTION_PREP_QUOTES } from './data/intentionPrep';
import { EATING_PREP_QUOTES } from './data/eatingPrep';

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '', titleEn: '10 Minutes Meditation', titleMy: '၁၀ မိနစ် တရားထိုင်ပါ', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '', titleEn: 'Notice 10 Intentions', titleMy: 'စေတနာ (၁၀)ခု သတိပြုပါ', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', timeRange: '', titleEn: 'Say Thank You (10 Times)', titleMy: 'ကျေးဇူးတင်ပါ အကြိမ် (၁၀)ခါ', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', timeRange: '', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Dhamma Part 1", titleMy: "တရားတော် (၁)", isCompleted: false },
  { id: 2, titleEn: "Dhamma Part 2", titleMy: "တရားတော် (၂)", isCompleted: false },
  { id: 3, titleEn: "Dhamma Part 3", titleMy: "တရားတော် (၃)", isCompleted: false },
  { id: 4, titleEn: "Dhamma Part 4", titleMy: "တရားတော် (၄)", isCompleted: false },
  { id: 5, titleEn: "Dhamma Part 5", titleMy: "တရားတော် (၅)", isCompleted: false },
];

const STORAGE_KEY = 'mindful_project_v3';
const LANG_KEY = 'mindfulness_lang_pref';
const DRIVE_FOLDER_URL = "https://drive.google.com/drive/folders/1Shs1vGPm53EDBJMZHAVJeZHkYEqvI4cM?usp=sharing";

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
    document.documentElement.lang = lang;
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
      setErrorMessage(lang === 'my' ? "ဒေတာများ ပြန်လည်ရယူရန် မအောင်မြင်ပါ။" : "Failed to load data.");
    }
  }, [lang]);

  const saveToLocalStorage = (
    updatedTasks: MorningTask[], 
    updatedAudio: AudioGuide[], 
    updatedWisdom: WisdomResponse | null
  ) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        audioGuides: updatedAudio,
        wisdom: updatedWisdom
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
      setSuccessMessage(lang === 'my' ? "သိမ်းဆည်းပြီးပါပြီ" : "Progress Saved");
      setTimeout(() => setSuccessMessage(null), 2000);
    } catch (e) {
      setErrorMessage(lang === 'my' ? "သိမ်းဆည်းရန် နေရာမလုံလောက်ပါ။" : "Storage Error.");
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveToLocalStorage(updated, audioGuides, wisdom);
  };

  const toggleAudio = (id: number) => {
    const updated = audioGuides.map(a => a.id === id ? { ...a, isCompleted: !a.isCompleted } : a);
    setAudioGuides(updated);
    saveToLocalStorage(tasks, updated, wisdom);
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveToLocalStorage(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const getQuotes = () => {
    switch(activeModalType) {
      case 'meditation': return MEDITATION_PREP_QUOTES;
      case 'gratitude': return GRATITUDE_PREP_QUOTES;
      case 'intention': return INTENTION_PREP_QUOTES;
      case 'eating': return EATING_PREP_QUOTES;
      default: return MEDITATION_PREP_QUOTES;
    }
  };

  const currentQuotes = getQuotes();
  const completedTasksCount = tasks.filter(t => t.isCompleted).length;
  const progressPercent = Math.round((completedTasksCount / tasks.length) * 100);

  const t = {
    title: lang === 'my' ? "ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန်" : "Wisdom-Guided Mindfulness",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ နာယူပါ" : "Listen before practice",
    completed: lang === 'my' ? "နာပြီး" : "Heard",
    prepBtn: lang === 'my' ? "တရားအကြိုလမ်းညွှန်" : "Prep Guide",
    heartBtn: lang === 'my' ? "ကျေးဇူးတရားလမ်းညွှန်" : "Heart Guide",
    intentionBtn: lang === 'my' ? "စေတနာလမ်းညွှန်" : "Intention Guide",
    eatingBtn: lang === 'my' ? "စားသုံးမှုလမ်းညွှန်" : "Eating Guide",
    prepTitle: lang === 'my' ? "ဝိပဿနာအကြိုလမ်းညွှန်" : "Vipassana Prep",
    heartTitle: lang === 'my' ? "နှလုံးသားဖွင့်ပွဲလမ်းညွှန်" : "Heart Opening",
    intentionTitle: lang === 'my' ? "စေတနာသတိပြုခြင်းလမ်းညွှန်" : "Intention Awareness",
    eatingTitle: lang === 'my' ? "သတိဖြင့်စားသုံးခြင်းလမ်းညွှန်" : "Mindful Eating",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
    discipline: lang === 'my' ? "နေ့စဉ်ကျင့်ဝတ်" : "Daily Discipline",
    undo: lang === 'my' ? "ဖျက်ရန်" : "Undo",
    completeTask: lang === 'my' ? "ပြီးပါပြီ" : "Done",
    close: lang === 'my' ? "ပိတ်ရန်" : "Close",
    next: lang === 'my' ? "နောက်သို့" : "Next",
    back: lang === 'my' ? "ရှေ့သို့" : "Back",
    progress: lang === 'my' ? "ပြီးစီးမှု" : "Progress",
  };

  return (
    <main id="main-content" className={`max-w-2xl mx-auto px-4 py-8 md:py-12 ${lang === 'my' ? 'lang-my' : ''}`}>
      {/* Accessibility Optimized Header */}
      <div className="flex items-center justify-between mb-8 sticky top-0 z-40 bg-[#EDF1E4]/90 backdrop-blur-md py-4 border-b border-gray-200/20">
        <div className="flex items-center gap-3" aria-label={`Current Progress: ${progressPercent}%`}>
            <div className="w-10 h-10 rounded-full bg-[#006D77] flex items-center justify-center text-white font-bold shadow-lg">
                {progressPercent}%
            </div>
            <div className="hidden sm:block">
                <p className="text-[10px] uppercase tracking-widest font-bold text-teal-900/60">{t.progress}</p>
                <div className="w-24 h-1.5 bg-gray-200 rounded-full mt-0.5 overflow-hidden">
                    <div className="h-full bg-[#B8860B] transition-all duration-700" style={{ width: `${progressPercent}%` }}></div>
                </div>
            </div>
        </div>

        <nav className="bg-white/60 p-1 rounded-2xl flex items-center shadow-sm border border-white/40 glass-card" aria-label="Language selector">
          <button 
            onClick={() => setLang('my')}
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-teal-900/60 hover:text-teal-900'}`}
            aria-pressed={lang === 'my'}
          >မြန်မာ</button>
          <button 
            onClick={() => setLang('en')}
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-teal-900/60 hover:text-teal-900'}`}
            aria-pressed={lang === 'en'}
          >EN</button>
        </nav>
      </div>

      <header className="text-center mb-10 fade-content">
        <h1 className="text-3xl md:text-4xl font-bold text-[#006D77] mb-2 leading-tight">{t.title}</h1>
        <div className="h-1 w-12 bg-[#B8860B] mx-auto rounded-full opacity-40" aria-hidden="true"></div>
      </header>

      {/* Audio Sanctuary Section */}
      <section className="bg-[#006D77] rounded-[2.5rem] p-6 md:p-10 mb-8 text-white shadow-2xl relative overflow-hidden fade-content" aria-labelledby="audio-heading">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16" aria-hidden="true"></div>
        <div className="relative z-10">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 id="audio-heading" className="text-xl font-bold">{t.audioTitle}</h2>
              <p className="text-teal-100/70 text-xs italic">{t.audioSubtitle}</p>
            </div>
            <a href={DRIVE_FOLDER_URL} target="_blank" rel="noopener noreferrer" 
               aria-label="Open Dhamma Folder on Google Drive"
               className="bg-[#B8860B] p-3 rounded-2xl shadow-lg active:scale-90 transition-transform hover:bg-[#9a700a]">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
            </a>
          </div>

          <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
            {audioGuides.map((guide) => (
              <button key={guide.id} onClick={() => toggleAudio(guide.id)}
                aria-label={`${guide.titleEn} - ${guide.isCompleted ? 'Completed' : 'Not started'}`}
                className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all border-2 active-scale ${guide.isCompleted ? 'bg-white/20 border-white/40 shadow-inner' : 'bg-white/5 border-white/10 hover:border-white/30'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-2 text-xs font-bold ${guide.isCompleted ? 'bg-[#B8860B] text-white' : 'bg-white/10 text-white'}`}>
                  {guide.isCompleted ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20" aria-hidden="true"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"/></svg> : guide.id}
                </div>
                <span className="text-[10px] font-bold opacity-80 truncate w-full text-center px-1 uppercase tracking-tight">{guide.isCompleted ? t.completed : `Part ${guide.id}`}</span>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Wisdom Card Section */}
      <section className="bg-white rounded-[2rem] p-8 shadow-xl border-t-4 border-[#B8860B] mb-8 relative fade-content glass-card" aria-labelledby="wisdom-heading">
        <h2 id="wisdom-heading" className="sr-only">Daily Wisdom</h2>
        {wisdom ? (
          <div className="space-y-6">
            <div className="flex items-center justify-between text-teal-900/50">
                <span className="text-[10px] font-bold uppercase tracking-widest">{lang === 'my' ? wisdom.quote.categoryMy : wisdom.quote.categoryEn}</span>
                <span className="text-[9px] font-mono">Q-{wisdom.quote.id}</span>
            </div>
            <p className="text-xl md:text-2xl text-gray-900 font-serif italic leading-relaxed text-center">
                "{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"
            </p>
            <div className="bg-[#FDFDFD] p-5 rounded-2xl border border-teal-50 italic text-sm text-gray-600 text-center">
                {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
            </div>
          </div>
        ) : (
          <div className="py-8 text-center text-teal-900/40 italic text-sm">
            {lang === 'my' ? "တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် အောက်ပါခလုတ်ကို နှိပ်ပါ။" : "Tap below to receive morning wisdom..."}
          </div>
        )}
        <div className="mt-8 flex justify-center">
          <button onClick={handleFetchWisdom} disabled={loadingWisdom}
            className="px-8 py-4 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl hover:bg-[#005a63] transition-all active-scale disabled:opacity-50 flex items-center gap-2">
            {loadingWisdom ? t.seeking : t.genBtn}
            {!loadingWisdom && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
          </button>
        </div>
      </section>

      {/* Daily Discipline List */}
      <section className="space-y-4 mb-16 fade-content" aria-labelledby="tasks-heading">
        <h2 id="tasks-heading" className="text-xl font-bold text-[#006D77] px-2 flex items-center gap-2 mb-6">
          <span className="w-1.5 h-6 bg-[#B8860B] rounded-full" aria-hidden="true"></span>
          {t.discipline}
        </h2>
        {tasks.map(task => (
          <article key={task.id} className={`p-6 rounded-[2rem] border transition-all duration-300 glass-card ${task.isCompleted ? 'bg-white/40 border-green-100 opacity-70' : 'bg-white border-white/20 shadow-sm hover:shadow-md'}`}>
            <div className="flex flex-col gap-4">
              <div className="flex items-start justify-between">
                <div>
                  <h3 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-400' : 'text-gray-900'}`}>
                    {lang === 'my' ? task.titleMy : task.titleEn}
                  </h3>
                  <p className={`mt-2 text-sm leading-relaxed ${task.isCompleted ? 'text-gray-400' : 'text-teal-900/70'}`}>
                    {lang === 'my' ? task.descriptionMy : task.descriptionEn}
                  </p>
                </div>
                <div className={`w-3 h-3 rounded-full flex-shrink-0 mt-1.5 ${task.isCompleted ? 'bg-green-500' : 'bg-[#B8860B] shadow-sm'}`} aria-hidden="true"></div>
              </div>

              <div className="flex items-center justify-between gap-2 mt-2">
                <div className="flex gap-2">
                    {!task.isCompleted && task.id === '1' && (
                        <button onClick={() => { setActiveModalType('meditation'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-amber-50 text-[#B8860B] rounded-xl text-[10px] font-bold border border-amber-200 active-scale hover:bg-amber-100">{t.prepBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '2' && (
                        <button onClick={() => { setActiveModalType('intention'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-teal-50 text-[#006D77] rounded-xl text-[10px] font-bold border border-teal-200 active-scale hover:bg-teal-100">{t.intentionBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '3' && (
                        <button onClick={() => { setActiveModalType('gratitude'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-red-50 text-red-700 rounded-xl text-[10px] font-bold border border-red-200 active-scale hover:bg-red-100">{t.heartBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '4' && (
                        <button onClick={() => { setActiveModalType('eating'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-green-50 text-green-800 rounded-xl text-[10px] font-bold border border-green-200 active-scale hover:bg-green-100">{t.eatingBtn}</button>
                    )}
                </div>
                <button onClick={() => toggleTask(task.id)}
                  aria-label={task.isCompleted ? `Mark ${task.titleEn} as incomplete` : `Mark ${task.titleEn} as complete`}
                  className={`px-6 py-3 rounded-2xl font-bold text-xs transition-all active-scale flex items-center gap-2 ${task.isCompleted ? 'bg-gray-200 text-gray-500' : 'bg-[#006D77] text-white shadow-md hover:bg-[#005a63]'}`}>
                  {task.isCompleted ? t.undo : t.completeTask}
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d={task.isCompleted ? "M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" : "M5 13l4 4L19 7"}/></svg>
                </button>
              </div>
            </div>
          </article>
        ))}
      </section>

      {/* Modal - Accessibility Optimized */}
      {showPrepModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/60 backdrop-blur-sm transition-opacity"
             role="dialog" aria-modal="true" aria-labelledby="modal-title"
             onClick={() => setShowPrepModal(false)}>
          <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh] sm:max-h-[85vh] animate-fade-in"
               onClick={e => e.stopPropagation()}>
            <div className={`p-6 md:p-8 text-white relative transition-colors duration-500 ${
                activeModalType === 'meditation' ? 'bg-[#B8860B]' : 
                activeModalType === 'gratitude' ? 'bg-[#E63946]' : 
                activeModalType === 'intention' ? 'bg-[#006D77]' : 'bg-[#6D775D]'
            }`}>
              <button type="button" onClick={() => setShowPrepModal(false)}
                className="absolute top-4 right-4 p-2 hover:bg-white/20 rounded-full transition-colors z-[110]" aria-label="Close modal">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <p id="modal-title" className="text-[10px] font-bold uppercase tracking-widest mb-1 opacity-80">
                {activeModalType === 'meditation' ? t.prepTitle : activeModalType === 'gratitude' ? t.heartTitle : activeModalType === 'intention' ? t.intentionTitle : t.eatingTitle}
              </p>
              <div className="flex items-center gap-4">
                <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 md:p-12">
              <div className="fade-content" key={`${activeModalType}-${prepStep}`}>
                <blockquote className={`border-l-4 pl-6 relative ${
                    activeModalType === 'meditation' ? 'border-[#B8860B]' : 
                    activeModalType === 'gratitude' ? 'border-[#E63946]' : 
                    activeModalType === 'intention' ? 'border-[#006D77]' : 'border-[#6D775D]'
                }`}>
                   <p className="text-xl text-gray-900 font-serif leading-relaxed italic">
                    "{lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}"
                   </p>
                </blockquote>
                <p className="mt-8 flex justify-end text-[10px] text-teal-900/30 font-mono uppercase tracking-widest">
                  Source: {currentQuotes[prepStep].source}
                </p>
              </div>
            </div>

            <nav className="p-6 border-t border-gray-100 flex items-center justify-between bg-gray-50/80" aria-label="Modal navigation">
              <div className="flex gap-1.5" aria-hidden="true">
                {currentQuotes.slice(0, 10).map((_, i) => (
                  <div key={i} className={`w-1 h-1 rounded-full transition-all ${i === prepStep ? `w-4 bg-[#006D77]` : 'bg-gray-300'}`}></div>
                ))}
              </div>
              <div className="flex gap-2">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-4 py-2 border border-gray-300 rounded-xl text-[10px] font-bold text-teal-900/60 uppercase tracking-widest active-scale hover:bg-white">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button onClick={() => setPrepStep(s => s + 1)} 
                    className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale hover:bg-[#005a63]">
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} 
                    className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale hover:bg-[#005a63]">
                    {t.close}
                  </button>
                )}
              </div>
            </nav>
          </div>
        </div>
      )}

      {/* Dynamic Feedback Toast */}
      {successMessage && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-6 py-4 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs" role="status">
          {successMessage}
        </div>
      )}

      <footer className="mt-12 text-center pb-8 opacity-40 border-t border-gray-200 pt-8">
        <p className="text-[10px] tracking-[0.3em] font-bold text-teal-900/60 uppercase">
          Mindful Project / {new Date().getFullYear()}
        </p>
      </footer>
    </main>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { WHAT_PROGRAM_QUOTES, ProgramQuote } from "../data/wisdom";

export interface WisdomResponse {
  quote: ProgramQuote;
  reflectionEn: string;
  reflectionMy: string;
}

export const generateDailyWisdom = async (tasksCompleted: number): Promise<WisdomResponse> => {
  // Creating a new instance right before the call ensures up-to-date API key usage
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const randomQuote = WHAT_PROGRAM_QUOTES[Math.floor(Math.random() * WHAT_PROGRAM_QUOTES.length)];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a mindfulness guide for "The WHAT Program" (Wisdom Talk). 
      Here is today's core quote from the program: 
      "${randomQuote.textEn}" (${randomQuote.textMy})

      The user has completed ${tasksCompleted} morning tasks. 
      Provide a short, 2-sentence morning guidance/reflection that expands on this quote for today's practice.
      Format your response strictly as:
      EN: [English Reflection]
      MY: [Myanmar Reflection]`,
      config: {
        temperature: 0.7,
        maxOutputTokens: 300,
      }
    });

    const text = response.text || "";
    const enMatch = text.match(/EN:\s*(.*)/i);
    const myMatch = text.match(/MY:\s*(.*)/i);

    return {
      quote: randomQuote,
      reflectionEn: enMatch ? enMatch[1].trim() : "Observe the natural flow of your breath and mind today.",
      reflectionMy: myMatch ? myMatch[1].trim() : "ယနေ့တွင် သင်၏ ထွက်လေဝင်လေနှင့် စိတ်၏ အစဉ်ကို သတိဖြင့် စောင့်ကြည့်ပါ။"
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      quote: randomQuote,
      reflectionEn: "Focus on the present moment as the foundation of your day.",
      reflectionMy: "ယနေ့၏ အခြေခံအဖြစ် ပစ္စုပ္ပန်တည့်တည့်တွင် အာရုံစိုက်ပါ။"
    };
  }
};

