                    <div className="h-full bg-[#B8860B] transition-all duration-700" style={{ width: `${progressPercent}%` }}></div>
                </div>
            </div>
        </div>

        <nav className="bg-white/60 p-1 rounded-2xl flex items-center shadow-sm border border-white/40 glass-card" aria-label="Language selector">
          <button 
            onClick={() => setLang('my')}
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-teal-900/60 hover:text-teal-900'}`}
