              <div className="flex gap-2">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-4 py-2 border border-gray-300 rounded-xl text-[10px] font-bold text-teal-900/60 uppercase tracking-widest active-scale hover:bg-white">
