    completed: lang === 'my' ? "နာပြီး" : "Heard",
    prepBtn: lang === 'my' ? "တရားအကြိုလမ်းညွှန်" : "Prep Guide",
    heartBtn: lang === 'my' ? "ကျေးဇူးတရားလမ်းညွှန်" : "Heart Guide",
    intentionBtn: lang === 'my' ? "စေတနာလမ်းညွှန်" : "Intention Guide",
    eatingBtn: lang === 'my' ? "စားသုံးမှုလမ်းညွှန်" : "Eating Guide",
    prepTitle: lang === 'my' ? "ဝိပဿနာအကြိုလမ်းညွှန်" : "Vipassana Prep",
    heartTitle: lang === 'my' ? "နှလုံးသားဖွင့်ပွဲလမ်းညွှန်" : "Heart Opening",
    intentionTitle: lang === 'my' ? "စေတနာသတိပြုခြင်းလမ်းညွှန်" : "Intention Awareness",
    eatingTitle: lang === 'my' ? "သတိဖြင့်စားသုံးခြင်းလမ်းညွှန်" : "Mindful Eating",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
