import { createClient } from '@supabase/supabase-js';
import { MorningTask, AudioGuide } from '../types';
import { WisdomResponse } from './gemini';

const supabaseUrl = 'https://ebxcirakgqzefjfdxvao.supabase.co';
const supabaseKey = 'sb_publishable_gdqjrCOPmseQiTPXE8jDMw_V1dn1qiR';

export const supabase = createClient(supabaseUrl, supabaseKey);

export interface SyncData {
  student_id: string;
  date: string;
  tasks: MorningTask[];
  audio_guides: AudioGuide[];
  wisdom: WisdomResponse | null;
  progress_percent: number;
}

export const syncProgress = async (data: SyncData) => {
  if (!data.student_id) return null;

  const { data: result, error } = await supabase
    .from('student_progress')
    .upsert({
      student_id: data.student_id,
      date: data.date,
      tasks: data.tasks,
      audio_guides: data.audio_guides,
      wisdom: data.wisdom,
      progress_percent: data.progress_percent,
      updated_at: new Date().toISOString()
    }, { onConflict: 'student_id,date' });

  if (error) console.error('Supabase Sync Error:', error);
  return result;
};

export const fetchTodayProgress = async (studentId: string, date: string) => {
  const { data, error } = await supabase
    .from('student_progress')
    .select('*')
    .eq('student_id', studentId)
    .eq('date', date)
    .single();

  if (error && error.code !== 'PGRST116') console.error('Supabase Fetch Error:', error);
  return data;
};

export const fetchStreak = async (studentId: string) => {
  const { data, error } = await supabase
    .from('student_progress')
    .select('date')
    .eq('student_id', studentId);

  if (error) return 0;

  const uniqueDays = new Set(data.map(d => d.date));
  return uniqueDays.size;
};

export const fetchHistory = async (studentId: string) => {
  const { data, error } = await supabase
    .from('student_progress')
    .select('date, progress_percent')
    .eq('student_id', studentId)
    .order('date', { ascending: false })
    .limit(7);

  if (error) return [];
  return data || [];
};

