          <button onClick={() => setLang('en')} className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-teal-900/60 hover:text-teal-900'}`}>EN</button>
        </nav>
      </div>

      <header className="text-center mb-10 fade-content">
        <h1 className={`text-3xl md:text-4xl font-bold text-[#006D77] mb-2 ${lang === 'my' ? 'leading-[1.1]' : 'leading-tight'}`}>
          {lang === 'my' ? (
            <>
              <span className="block sm:inline">ပညာဖြင့် လမ်းညွှန်သော</span>
              <br className="sm:hidden" />
              <span className="block sm:inline sm:ml-2">သတိပဋ္ဌာန်</span>
            </>
          ) : (
            <>
              <span className="block sm:inline">Wisdom-Guided</span>
              <br className="sm:hidden" />
              <span className="block sm:inline sm:ml-2">Mindfulness</span>
            </>
          )}
        </h1>
        <div className="h-1 w-12 bg-[#B8860B] mx-auto rounded-full opacity-40" aria-hidden="true"></div>
      </header>

      {/* Audio Section */}
      <section className="bg-[#006D77] rounded-[2.5rem] p-6 md:p-10 mb-8 text-white shadow-2xl relative overflow-hidden fade-content">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16" aria-hidden="true"></div>
        <div className="relative z-10">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 className="text-xl font-bold">{t.audioTitle}</h2>
              <p className="text-teal-100/70 text-xs italic">{t.audioSubtitle}</p>
            </div>
            <a href={DRIVE_FOLDER_URL} target="_blank" rel="noopener noreferrer" className="bg-[#B8860B] p-3 rounded-2xl shadow-lg active:scale-90 transition-transform hover:bg-[#9a700a]">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
            </a>
          </div>
          <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
            {audioGuides.map((guide) => (
              <button key={guide.id} onClick={() => toggleAudio(guide.id)} className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all border-2 active-scale ${guide.isCompleted ? 'bg-white/20 border-white/40 shadow-inner' : 'bg-white/5 border-white/10 hover:border-white/30'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-2 text-xs font-bold ${guide.isCompleted ? 'bg-[#B8860B] text-white' : 'bg-white/10 text-white'}`}>
                  {guide.isCompleted ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"/></svg> : guide.id}
                </div>
                <span className="text-[10px] font-bold opacity-80 truncate w-full text-center px-1 uppercase tracking-tight">{guide.isCompleted ? t.completed : `Part ${guide.id}`}</span>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Wisdom Card */}
      <section className="bg-white rounded-[2rem] p-8 shadow-xl border-t-4 border-[#B8860B] mb-8 relative fade-content glass-card">
        {wisdom ? (
          <div className="space-y-6">
            <div className="flex items-center justify-between text-teal-900/50">
                <span className="text-[10px] font-bold uppercase tracking-widest">{lang === 'my' ? wisdom.quote.categoryMy : wisdom.quote.categoryEn}</span>
                <span className="text-[9px] font-mono">Q-{wisdom.quote.id}</span>
            </div>
            <p className="text-xl md:text-2xl text-gray-900 font-serif italic leading-relaxed text-center">"{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"</p>
            <div className="bg-[#FDFDFD] p-5 rounded-2xl border border-teal-50 italic text-sm text-gray-600 text-center leading-relaxed">{lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}</div>
          </div>
        ) : (
          <div className="py-8 text-center text-teal-900/40 italic text-sm">{lang === 'my' ? "တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် အောက်ပါခလုတ်ကို နှိပ်ပါ။" : "Tap below to receive morning wisdom..."}</div>
        )}
        <div className="mt-8 flex justify-center">
          <button onClick={handleFetchWisdom} disabled={loadingWisdom || !studentId} className="px-8 py-4 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl hover:bg-[#005a63] transition-all active-scale disabled:opacity-30 flex items-center gap-2">
            {loadingWisdom ? t.seeking : t.genBtn}
            {!loadingWisdom && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
          </button>
        </div>
      </section>

      {/* Discipline List */}
      <section className="space-y-4 mb-16 fade-content">
        <h2 className="text-xl font-bold text-[#006D77] px-2 flex items-center gap-2 mb-6">
          <span className="w-1.5 h-6 bg-[#B8860B] rounded-full" aria-hidden="true"></span>
          {t.discipline}
        </h2>
        {tasks.map(task => (
          <article key={task.id} className={`p-6 rounded-[2rem] border transition-all duration-300 glass-card ${task.isCompleted ? 'bg-white/40 border-green-100 opacity-70' : 'bg-white border-white/20 shadow-sm hover:shadow-md'}`}>
            <div className="flex flex-col gap-4">
              <div className="flex items-start justify-between">
                <div className="flex-grow pr-4">
                  <h3 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-400' : 'text-gray-900'}`}>{lang === 'my' ? task.titleMy : task.titleEn}</h3>
                  <p className={`mt-2 text-sm leading-relaxed ${task.isCompleted ? 'text-gray-400' : 'text-teal-900/70'}`}>{lang === 'my' ? task.descriptionMy : task.descriptionEn}</p>
                </div>
                <div className={`w-3 h-3 rounded-full flex-shrink-0 mt-1.5 ${task.isCompleted ? 'bg-green-500' : 'bg-[#B8860B] shadow-sm'}`} aria-hidden="true"></div>
              </div>
              <div className="flex items-center justify-between gap-2 mt-2">
                <div className="flex gap-2">
                    {['1','2','3','4'].includes(task.id) && !task.isCompleted && (
                      <button onClick={() => { 
                        setActiveModalType(task.id === '1' ? 'meditation' : task.id === '2' ? 'intention' : task.id === '3' ? 'gratitude' : 'eating'); 
                        setShowPrepModal(true); setPrepStep(0); 
                      }} className="px-4 py-2 bg-white/50 border border-teal-100 rounded-xl text-[10px] font-bold text-[#006D77] uppercase active-scale">
                        {task.id === '1' ? t.prepBtn : task.id === '2' ? t.intentionBtn : task.id === '3' ? t.heartBtn : t.eatingBtn}
                      </button>
                    )}
                </div>
                <button onClick={() => toggleTask(task.id)} disabled={!studentId} className={`px-6 py-3 rounded-2xl font-bold text-xs transition-all active-scale flex items-center gap-2 disabled:opacity-30 ${task.isCompleted ? 'bg-gray-200 text-gray-500' : 'bg-[#006D77] text-white shadow-md'}`}>
                  {task.isCompleted ? t.undo : t.completeTask}
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d={task.isCompleted ? "M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" : "M5 13l4 4L19 7"}/></svg>
                </button>
              </div>
            </div>
          </article>
        ))}
      </section>

      {/* Modals & Feedback */}
      {showPrepModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/60 backdrop-blur-sm" role="dialog" aria-modal="true" onClick={() => setShowPrepModal(false)}>
          <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-fade-in" onClick={e => e.stopPropagation()}>
            <div className={`p-6 md:p-8 text-white relative ${activeModalType === 'meditation' ? 'bg-[#B8860B]' : activeModalType === 'gratitude' ? 'bg-[#E63946]' : activeModalType === 'intention' ? 'bg-[#006D77]' : 'bg-[#6D775D]'}`}>
              <button onClick={() => setShowPrepModal(false)} className="absolute top-4 right-4 p-2 hover:bg-white/20 rounded-full" aria-label="Close"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg></button>
              <div className="flex items-center gap-4">
                <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>
            <div className="flex-grow overflow-y-auto p-8 md:p-12">
              <blockquote className="border-l-4 pl-6 border-[#006D77]"><p className="text-xl text-gray-900 font-serif leading-relaxed italic">"{lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}"</p></blockquote>
            </div>
            <nav className="p-6 border-t border-gray-100 flex items-center justify-between bg-gray-50/80">
              <div className="flex gap-2">
                {prepStep > 0 && <button onClick={() => setPrepStep(s => s - 1)} className="px-4 py-2 border border-gray-300 rounded-xl text-[10px] font-bold text-teal-900/60 uppercase">{t.back}</button>}
                {prepStep < currentQuotes.length - 1 ? <button onClick={() => setPrepStep(s => s + 1)} className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase">{t.next}</button> : <button onClick={() => setShowPrepModal(false)} className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase">{t.close}</button>}
              </div>
            </nav>
          </div>
        </div>
      )}

      {successMessage && <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-teal-900 text-white px-6 py-4 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs" role="status">{successMessage}</div>}

      <footer className="mt-12 text-center pb-8 opacity-40 border-t border-gray-200 pt-8">
        <p className="text-[10px] tracking-[0.3em] font-bold text-teal-900/60 uppercase">Mindful Project / {new Date().getFullYear()}</p>
      </footer>
    </main>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { syncProgress, fetchTodayProgress, fetchStreak, fetchHistory, fetchCommunityProgress } from './services/supabase';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
import { INTENTION_PREP_QUOTES } from './data/intentionPrep';
import { EATING_PREP_QUOTES } from './data/eatingPrep';

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '', titleEn: '10 Minutes Meditation', titleMy: '၁၀ မိနစ် တရားထိုင်ပါ', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '', titleEn: 'Notice 10 Intentions', titleMy: 'စေတနာ (၁၀)ခု သတိပြုပါ', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', timeRange: '', titleEn: 'Say Thank You (10 Times)', titleMy: 'ကျေးဇူးတင်ပါ အကြိမ် (၁၀)ခါ', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', timeRange: '', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Dhamma Part 1", titleMy: "တရားတော် (၁)", isCompleted: false },
  { id: 2, titleEn: "Dhamma Part 2", titleMy: "တရားတော် (၂)", isCompleted: false },
  { id: 3, titleEn: "Dhamma Part 3", titleMy: "တရားတော် (၃)", isCompleted: false },
  { id: 4, titleEn: "Dhamma Part 4", titleMy: "တရားတော် (၄)", isCompleted: false },
  { id: 5, titleEn: "Dhamma Part 5", titleMy: "တရားတော် (၅)", isCompleted: false },
];

const STORAGE_KEY = 'mindful_project_v3';
const LANG_KEY = 'mindfulness_lang_pref';
const STUDENT_ID_KEY = 'mindful_student_id';
const DRIVE_FOLDER_URL = "https://drive.google.com/drive/folders/1Shs1vGPm53EDBJMZHAVJeZHkYEqvI4cM?usp=sharing";
const ID_FINDER_URL = "https://student-id.mindset-it.online/";

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

interface CommunityEntry {
  student_id: string;
  date: string;
  progress_percent: number;
  updated_at: string;
}

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => (localStorage.getItem(LANG_KEY) as Language) || 'my');
  const [studentId, setStudentId] = useState<string>(() => localStorage.getItem(STUDENT_ID_KEY) || '');
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [streakCount, setStreakCount] = useState(0);
  const [history, setHistory] = useState<{date: string, progress_percent: number}[]>([]);
  const [communityData, setCommunityData] = useState<CommunityEntry[]>([]);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  const todayDate = new Date().toISOString().split('T')[0];

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
    document.documentElement.lang = lang;
  }, [lang]);

  useEffect(() => {
    localStorage.setItem(STUDENT_ID_KEY, studentId);
    if (studentId) {
      loadInitialData();
      updateStats();
    }
    loadCommunity();
  }, [studentId]);

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const dayNum = date.getDate();
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const month = months[date.getMonth()];
    const dayName = days[date.getDay()];
    return `${dayName}, ${dayNum} ${month}`;
  };

  const getDistinctIdPart = (id: string) => {
    const numbers = id.match(/\d+/g);
    if (numbers) return numbers.join('');
    return id.slice(-3).toUpperCase();
  };

  const loadInitialData = async () => {
    if (studentId) {
      const cloudData = await fetchTodayProgress(studentId, todayDate);
      if (cloudData) {
        setTasks(cloudData.tasks);
        setAudioGuides(cloudData.audio_guides);
        setWisdom(cloudData.wisdom);
        return;
      }
    }

    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.date === todayDate) {
        setTasks(parsed.tasks || INITIAL_TASKS);
        setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
        setWisdom(parsed.wisdom || null);
      }
    }
  };

  const loadCommunity = async () => {
    const data = await fetchCommunityProgress();
    setCommunityData(data);
  };

  const updateStats = async () => {
    if (studentId) {
      const [count, hist] = await Promise.all([
        fetchStreak(studentId),
        fetchHistory(studentId)
      ]);
      setStreakCount(count);
      setHistory(hist.reverse());
    }
  };

  const saveAndSync = async (updatedTasks: MorningTask[], updatedAudio: AudioGuide[], updatedWisdom: WisdomResponse | null) => {
    const progressPercent = Math.round(((updatedTasks.filter(t => t.isCompleted).length) / updatedTasks.length) * 100);

    const stateToSave = { date: todayDate, tasks: updatedTasks, audioGuides: updatedAudio, wisdom: updatedWisdom };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));

    if (studentId) {
      setIsSyncing(true);
      await syncProgress({
        student_id: studentId,
        date: todayDate,
        tasks: updatedTasks,
        audio_guides: updatedAudio,
        wisdom: updatedWisdom,
        progress_percent: progressPercent
      });
      setIsSyncing(false);
      updateStats();
      loadCommunity();
      setSuccessMessage(lang === 'my' ? "အချက်အလက်များကို သိမ်းဆည်းပြီးပါပြီ" : "Progress Synced to Cloud");
      setTimeout(() => setSuccessMessage(null), 2000);
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveAndSync(updated, audioGuides, wisdom);
  };

  const toggleAudio = (id: number) => {
    const updated = audioGuides.map(a => a.id === id ? { ...a, isCompleted: !a.isCompleted } : a);
    setAudioGuides(updated);
    saveAndSync(tasks, updated, wisdom);
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveAndSync(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const currentQuotes = activeModalType === 'meditation' ? MEDITATION_PREP_QUOTES : 
                       activeModalType === 'gratitude' ? GRATITUDE_PREP_QUOTES : 
                       activeModalType === 'intention' ? INTENTION_PREP_QUOTES : EATING_PREP_QUOTES;

  const completedTasksCount = tasks.filter(t => t.isCompleted).length;
  const progressPercent = Math.round((completedTasksCount / tasks.length) * 100);

  const t = {
    titleEn: "Wisdom-Guided Mindfulness",
    studentIdLabel: lang === 'my' ? "ကျောင်းသား အမှတ်အသား" : "Student Identity",
    studentIdPlaceholder: lang === 'my' ? "ID ရိုက်ထည့်ပါ..." : "Enter ID...",
    idFinder: lang === 'my' ? "ID ရှာရန်" : "ID Finder",
    streak: lang === 'my' ? "ရက်ပေါင်း" : "Days Active",
    historyTitle: lang === 'my' ? "ယခင်ရက်များမှ ပြီးစီးမှု" : "Consistency Journey",
    communityTitle: lang === 'my' ? "ဓမ္မမိတ်ဆွေများ၏ လေ့ကျင့်မှု" : "Community Journey",
    communitySubtitle: lang === 'my' ? "တူညီသောလမ်းစဉ်တွင် လျှောက်လှမ်းနေသူများ" : "Practicing together on the path",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ နာယူပါ" : "Listen before practice",
    completed: lang === 'my' ? "နာပြီး" : "Heard",
    prepBtn: lang === 'my' ? "တရားအကြိုလမ်းညွှန်" : "Prep Guide",
    heartBtn: lang === 'my' ? "ကျေးဇူးတရားလမ်းညွှန်" : "Heart Guide",
    intentionBtn: lang === 'my' ? "စေတနာလမ်းညွှန်" : "Intention Guide",
    eatingBtn: lang === 'my' ? "စားသုံးမှုလမ်းညွှန်" : "Eating Guide",
    prepTitle: lang === 'my' ? "ဝိပဿနာအကြိုလမ်းညွှန်" : "Vipassana Prep",
    heartTitle: lang === 'my' ? "နှလုံးသားဖွင့်ပွဲလမ်းညွှန်" : "Heart Opening",
    intentionTitle: lang === 'my' ? "စေတနာသတိပြုခြင်းလမ်းညွှန်" : "Intention Awareness",
    eatingTitle: lang === 'my' ? "သတိဖြင့်စားသုံးခြင်းလမ်းညွှန်" : "Mindful Eating",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
